    ScriptsMappingComponent.prototype.save = function () {
        var _this = this;
        this.scripts = [];
        var flag;
        var selectedScripts = [];
        var allScripts = [];
        var duplicateStatus = true;
        this.dataSource.data.forEach(function (element) {
            // console.log('element',element)
            if (element.Selected) {
                flag = true;
                delete element['Selected'];
                _this.scripts.push(element);
            }
        });
        // delete element['Selected']
        if (flag) {
            var formData = new FormData();
            formData.append('Scripts', JSON.stringify(this.scripts));
            console.log('data for backend....', JSON.stringify(this.scripts));
            formData.append('Operation', 'Mapping');
            this.httpClient.post('/api/saveMappingKeywords', formData, { responseType: 'text' }).subscribe(function (data) {
                alert(data);
                _this.scriptsLoad();
            }, function (err) {
            });
        }
        else {
            alert('Select atleast one');
        }
    };
