    TagsTrainingComponent.prototype.getTeams = function (custID) {
        var _this = this;
        this.teams = [];
        if (this.selectedTeam != "") {
            this.teams.push(this.selectedTeam);
        }
        else {
            this.teams.push(this.chosenTeam);
        }
        this.httpClient.get('/api/getTagDatasetTeamNames/' + this.customerId).subscribe(function (data) {
            if (data['Teams'].length > 0) {
                data['Teams'].forEach(function (element) {
                    if (!_this.teams.includes(element)) {
                        _this.teams.push(element);
                    }
                });
            }
        });
        // this.httpClient.get('/api/getTeams/' + this.customerId).subscribe(data => {
        //   this.teams = data['Teams'];
        //   console.log(this.teams);
        // });
        this.httpClient.get('/api/getNoTagDatasetTeamNames/' + this.customerId).subscribe(function (data) {
            if (data['Teams'].length > 0) {
                data['Teams'].forEach(function (element) {
                    if (!_this.teams.includes(element)) {
                        _this.teams.push(element);
                    }
                });
            }
        });
    };
