    MappingDetailsComponent.prototype.dateChanged = function (event, rowIndex) {
        var _this = this;
        if (event.value) {
            var date = event.value;
            var index = this._findDate(date);
            if (index === -1) {
                //this.model.push(date);
                this.sampleArray[rowIndex].model.push(date);
            }
            else {
                //this.model.splice(index, 1);
                this.sampleArray[rowIndex].model.splice(index, 1);
            }
            //this.resetModel = new Date(0);
            if (!this.CLOSE_ON_SELECTED) {
                var closeFn_1 = this._picker.close;
                this._picker.close = function () { };
                this._picker['_popupComponentRef'].instance._calendar.monthView._createWeekCells();
                setTimeout(function () {
                    _this._picker.close = closeFn_1;
                });
            }
        }
    };
    MappingDetailsComponent.prototype.remove = function (date) {
        var index = this._findDate(date);
        this.model.splice(index, 1);
    };
    MappingDetailsComponent.prototype._findDate = function (date) {
        //return this.model.map((m) => +m).indexOf(+date);
        var rowIndex = this.rowSelectedinTable;
        return this.sampleArray[rowIndex].model.map(function (m) { return +m; }).indexOf(+date);
    };
