    MappingDetailsComponent.prototype.uploadApplicationDetails = function () {
        var _this = this;
        // this.saveSuccess=false;
        console.log("in upload application details...");
        var fileBrowser = this.fileInput.nativeElement;
        if (fileBrowser.files && fileBrowser.files[0] && this.chosenTeam != "") {
            this.loading = true;
            var formData = new FormData();
            formData.append("applicationDetails", fileBrowser.files[0]);
            this.httpService
                .post("/api/uploadApplicationDetails/" +
                this.customerId +
                "/" +
                this.chosenTeam, formData, { responseType: "text" })
                .subscribe(function (data) {
                if (data == "success") {
                    _this.loading = false;
                    _this.teamChange();
                    // this.saveFailure=false;
                    // this.saveSuccess=true;
                }
                else {
                    console.log("Oops!!, No any data received");
                    // this.saveSuccess=false;
                    // this.saveFailure=true;
                }
            });
            this.loading = false;
        }
        else {
            alert("Please choose the right Team and file..!");
        }
    };
