    MappingDetailsComponent.prototype.updateApplication = function (recordId, index) {
        var _this = this;
        this.teamId = [];
        if (this.chosenTeam1 == 'All') {
            this.teams1.forEach(function (index) {
                var val1 = _this.getKeyByValue(_this.teams1, index);
                _this.teamId.push(parseInt(val1) + 1);
            });
        }
        else {
            var val1 = this.getKeyByValue(this.teams1, this.chosenTeam1);
            this.teamId.push(parseInt(val1) + 1);
        }
        var modified_New_resource;
        if (recordId === 0) {
            this.appresourceMappingDetails[index].DatasetID = this.teamId;
            this.appresourceMappingDetails[index].resource_id = this.appresourceMappingDetails[index].temp_resource_id;
            modified_New_resource = this.appresourceMappingDetails[index];
        }
        else {
            modified_New_resource = this.appresourceMappingDetails[index];
        }
        //if (Object.keys(this.editedDocument).length != 0) {
        if (modified_New_resource != undefined) {
            if (modified_New_resource.temp_resource_id != undefined) {
                delete modified_New_resource.temp_resource_id;
            }
            var customerId = 1; //to be removed
            var datasetId = 1;
            //new start
            var dt = new Date();
            var month = dt.getMonth() + 1;
            var year = dt.getFullYear();
            var daysInMonth = new Date(year, month, 0).getDate();
            this.loading = true;
            this.httpService
                .put("/api/updateApplication/" + daysInMonth, modified_New_resource, 
            //new end
            {
                responseType: "text",
                headers: { "Content-Type": "application/json" },
            })
                .subscribe(function (updateResponse) {
                _this.loading = false;
                if (updateResponse == "success") {
                    _this.getlatestDataPostSave();
                    alert("Updated successfully!");
                    _this.cancelUpdate(index);
                    _this.teamChange();
                }
                else {
                    alert("failed to update!");
                }
            }, function (err) {
                _this.getlatestDataPostSave();
                console.log(err);
                _this.loading = false;
                throw '';
            });
            this.cancelUpdate(index);
            this.teamChange();
        }
        else {
            alert("Nothing to update!");
            this.cancelUpdate(index);
        }
    };
