    MappingDetailsComponent.prototype.deleteApplication = function (recordId, index) {
        var _this = this;
        this.confirmValue = confirm("Are you sure!, you want to delete this application?");
        if (this.confirmValue) {
            //alert(recordId) ;      
            this.appresourceMappingDetails.splice(index, 1);
            this.httpService
                .delete("/api/deleteAnalystMapping/" + this.customerId + "/" + this.chosenTeam1 + "/" +
                recordId, { responseType: "text" })
                .subscribe(function (data) {
                if (data == "success") {
                    _this.teamChange();
                    _this.resourceDetailsObj.teamChange();
                    _this.roasterDetialsObj.teamChange();
                }
                else {
                    console.log(data);
                }
            });
        }
    };
