    ResourceShiftDetailsComponent.prototype.validateDates = function (sDate, eDate) {
        this.todayDate = new Date();
        var firstDate = this.datePipe.transform(sDate, "dd-MM-yyyy");
        var secondDate = this.datePipe.transform(eDate, "dd-MM-yyyy");
        var latest_Date = this.datePipe.transform(this.todayDate, "dd-MM-yyyy");
        console.log('sdate.........', sDate);
        console.log('today.........', this.todayDate);
        console.log('latest.........', latest_Date);
        this.isValidDate = true;
        if ((firstDate == null || secondDate == null)) {
            this.error = { isError: true, errorMessage: 'Start date and end date are required.' };
            this.isValidDate = false;
        }
        if ((firstDate != null && secondDate != null) && ((secondDate) < (firstDate)) || (firstDate) < (latest_Date)) {
            this.error = { isError: true, errorMessage: 'End date should be grater then start date.' };
            this.isValidDate = false;
        }
        return this.isValidDate;
    };
