    TrainingComponent.prototype.getPredictedFields = function () {
        var _this = this;
        this.httpClient.get('/api/predictedfields/' + this.customerId + "/" + this.datasetID).subscribe(function (data) {
            console.log('in showInputOutput');
            if (data != null && data != "" && data['FieldSelections'] != "" && data['UniqueFields'] != "" && data['BestAlgoParams'] != '') {
                data['FieldSelections'].forEach(function (selection) {
                    if (selection['FieldsStatus'] == "Approved") {
                        var temp = selection['PredictedFields'];
                        temp.forEach(function (field) {
                            var x = _this.attributeList.find(function (attribute) { return attribute.Attribute === field.PredictedFieldName; });
                            var index = _this.attributeList.indexOf(x);
                            var temp1 = [];
                            var temp2 = [];
                            _this.selectedPredictedFields.push({ "id": index, "Attribute": field.PredictedFieldName });
                            field.InputFields.forEach(function (input, i) {
                                var x = _this.attributeList.find(function (attribute) { return attribute.Attribute === input; });
                                var index = _this.attributeList.indexOf(x);
                                temp1.push({ "id": index, "Attribute": input });
                            });
                            field.Additionalfields.forEach(function (input, i) {
                                var x = _this.attributeList.find(function (attribute) { return attribute.Attribute === input; });
                                var index = _this.attributeList.indexOf(x);
                                temp2.push({ "id": index, "Attribute": input });
                            });
                            _this.selectedAdditionalfields[field.PredictedFieldName] = temp2;
                            _this.selectedInputFields[field.PredictedFieldName] = temp1;
                        });
                    }
                });
                if (_this.selectedPredictedFields.length > 0) {
                    _this.predictedDropdownList = _this.attributeList.slice(0);
                    // this.inputDropdownList = this.attributeList.slice(0);
                    console.log("type of dropdown list is " + typeof (_this.predictedDropdownList));
                    // this.selectedPredictedFields.forEach(field => {
                    //   let temp = this.attributeList.find(deselectedField => deselectedField.Attribute === field.Attribute);
                    //   let index = this.attributeList.indexOf(temp);
                    //   this.inputDropdownList.splice(index, 1);
                    // });
                    data['UniqueFields'].forEach(function (field) {
                        var x = _this.attributeList.find(function (attribute) { return attribute.Attribute === field.FieldName; });
                        var index = _this.attributeList.indexOf(x);
                        var temp1 = [];
                        _this.selectedUniqueFields.push({ "id": index, "Attribute": field.FieldName });
                    });
                    _this.BestAlgorithmDetails = data['BestAlgoParams'];
                    console.log('BEST');
                    console.log(_this.BestAlgorithmDetails);
                }
                else {
                    _this.predictedDropdownList = _this.attributeList.slice(0);
                    // this.inputDropdownList = this.attributeList.slice(0);
                }
                console.log("Predicted fields chosen are " + _this.selectedPredictedFields);
                console.log("Input fields chosen are " + _this.selectedInputFields);
                console.log("Addtional Input fields are choosen" + _this.selectedAdditionalfields);
                _this.httpClient.get('/api/algorithms/' + _this.customerId + "/" + _this.datasetID + "/Approved").subscribe(function (data) {
                    if (data && data['PredictedFields'] != "") {
                        console.log("tesssssssssssssssssssssssssssssssssssst");
                        _this.approvedAlgorithms = true;
                    }
                    else {
                        _this.approvedAlgorithms = false;
                    }
                });
            }
            else {
                _this.predictedDropdownList = _this.attributeList.slice(0);
                // this.inputDropdownList = this.attributeList.slice(0);
            }
        });
    };
