    TrainingComponent.prototype.uploadTrainingData = function () {
        var _this = this;
        this.datasetDeleted = false;
        this.datasetEdited = false;
        this.datasetExists = false;
        this.uploadTrainingSuccess = false;
        this.attributeList = [];
        this.trainingMode = 'IIA';
        console.log('in uploadTrainingData');
        console.log("chosen team is " + this.chosenTeam);
        console.log("trainingMode " + this.trainingMode);
        var fileBrowser = this.fileInput.nativeElement;
        var temp = [];
        if (fileBrowser.files && fileBrowser.files[0]) {
            console.log(fileBrowser.files[0]);
            if (fileBrowser.files[0].type == 'text/csv' || fileBrowser.files[0].type == "application/x-zip-compressed" || fileBrowser.files[0].type == "application/vnd.ms-excel") {
                this.loading = true;
                var formData = new FormData();
                formData.append('trainingData', fileBrowser.files[0]);
                this.httpClient.post('/api/uploadTrainingData/' + this.customerId + '/' + this.chosenTeam + "/" + this.chosenTeam + "/" + this.trainingMode, formData, { responseType: 'text' })
                    .subscribe(function (data) {
                    if (data == "success") {
                        _this.loading = false;
                        _this.uploadTrainingSuccess = true;
                        _this.datasetExists = true;
                        _this.postResult = 'Training data uploaded successfully!';
                        _this.getTeams(_this.customerId);
                        _this.httpClient.get('/api/getTeamID/' + _this.customerId + "/" + _this.chosenTeam).subscribe(function (data) {
                            _this.teamID = parseInt(data.toString());
                            ;
                            _this.httpClient.get('/api/getDatasetID/' + _this.customerId + "/" + _this.teamID).subscribe(function (data) {
                                _this.datasetID = parseInt(data.toString());
                                _this.httpClient.get('/api/getDatasetDetails/' + _this.customerId + "/" + _this.datasetID).subscribe(function (data) {
                                    _this.selectedTeam = _this.chosenTeam;
                                    _this.datasetName = data['name'];
                                    _this.datasetCount = data['count'];
                                    _this.trainingMode = data['training_mode'];
                                    temp = data['fields'];
                                    temp.forEach(function (attribute, index) {
                                        _this.attributeList.push({ "id": index, "Attribute": attribute });
                                    });
                                    console.log("Attribute list is " + _this.attributeList);
                                    _this.uniqueFieldList = _this.attributeList.slice(0);
                                    _this.predictedDropdownList = _this.attributeList.slice(0);
                                    _this.getPredictedFields();
                                    _this.showAlgorithms();
                                    // this.inputDropdownList = this.attributeList.slice(0);
                                }, function (err) {
                                    _this.loading = false;
                                    console.log(err);
                                    throw "";
                                });
                            });
                        });
                    }
                    else {
                        _this.loading = false;
                        alert("couldn't upload the file! please try again");
                    }
                });
            }
            else {
                alert("Please attach Zip/CSV file");
            }
        }
    };
