    TrainingComponent.prototype.appendRecords = function () {
        var _this = this;
        this.recordsAdded = false;
        console.log('in appendRecords');
        console.log(this.fileInput.nativeElement.value);
        var fileBrowser = this.fileInput.nativeElement;
        if (fileBrowser.files[0].type != 'text/csv' && fileBrowser.files[0].type != "application/vnd.ms-excel") {
            this.recordsAdded = false;
            alert("Please upload CSV File");
            return;
        }
        var temp = [];
        if (fileBrowser.files[0].type == 'text/csv' || fileBrowser.files[0].type == "application/vnd.ms-excel") {
            if (fileBrowser.files && fileBrowser.files[0]) {
                this.addingRecords = true;
                var formData = new FormData();
                formData.append('trainingData', fileBrowser.files[0]);
                this.loading = true;
                this.httpClient.post('/api/uploadTrainingData/' + this.customerId + "/" + this.selectedTeam + "/" + this.selectedTeam + "/" + this.trainingMode, formData, { responseType: 'text' })
                    .subscribe(function (data) {
                    _this.loading = false;
                    if (data == 'success') {
                        _this.addingRecords = false;
                        _this.httpClient.get('/api/getTeamID/' + _this.customerId + "/" + _this.selectedTeam).subscribe(function (data) {
                            _this.teamID = parseInt(data.toString());
                            ;
                            _this.httpClient.get('/api/getDatasetID/' + _this.customerId + "/" + _this.teamID).subscribe(function (data) {
                                _this.datasetID = parseInt(data.toString());
                                _this.httpClient.get('/api/getDatasetDetails/' + _this.customerId + "/" + _this.datasetID).subscribe(function (data) {
                                    _this.datasetCount = data['count'];
                                });
                            });
                        });
                        _this.recordsAdded = true;
                        _this.message = "New records added successfully!";
                    }
                    else if (data == 'failure') {
                        _this.recordsAdded = true;
                        _this.message = 'Upload failed, please upload the right dataset with matching columns';
                    }
                    else {
                        _this.recordsAdded = true;
                        _this.message = data;
                    }
                }, function (err) {
                    _this.loading = false;
                    console.log(err);
                    throw "";
                });
            }
            else {
                this.addingRecords = false;
            }
        }
    };
    TrainingComponent.prototype.deleteDataset = function () {
        var _this = this;
        this.datasetDeleted = false;
        this.datasetEdited = false;
        this.uploadTrainingSuccess = false;
        this.approvedAlgorithms = false;
        this.selectedTeam = "";
        this.chosenTeam = "";
        this.httpClient.delete('/api/deleteDataset/' + this.customerId + "/" + this.datasetID, { responseType: 'text' })
            .subscribe(function (data) {
            _this.datasetDeleted = true;
            _this.datasetExists = false;
            _this.datasetName = "";
            _this.selectedInputFields = [];
            _this.selectedPredictedFields = [];
            _this.selectedUniqueFields = [];
            _this.router.navigateByUrl('').then(function (e) {
                if (e) {
                    console.log("Navigation is successful!");
                    _this.httpClient.get('/api/getNoDatasetTeamNames/' + _this.customerId).subscribe(function (data) {
                        if (data['Teams'].length > 0) {
                            _this.teamsNoDataset = data['Teams'];
                        }
                    });
                }
                else {
                    console.log("Navigation has failed!");
                }
            });
            console.log(data);
        }, function (err) {
            console.log(err);
            throw "";
        });
    };
